<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
         <div role="document" class="modal-dialog" style="max-width: 1400px !important;">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ modalTitle }}</h4>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div id="divDialogViewContracts" class="modal-body" style="height: auto; min-height: 0px; max-height: none;">
                    <div id="divDialogViewCCoptionTicket" class="w-100 listing">
                        <div class="table-responsive table-fix-header" style="max-height: 710px; overflow-y: auto;">
                            <table class="table table-bordered dt-responsive nowrap mt-0 mb-0">
                                <thead class="thead-bg">
                                    <tr>
                                        <th class="text-center font-weight-bold" width="10%">S.No</th>
                                        <th class="font-weight-bold" width="50%"> {{ GroupBy === 'Biller' ? $t('Contract') : $t('Biller') }}</th>
                                        <th style="width:12%">
                                            <span href="javascript:;">
                                                {{ $t('Flag') }}
                                            </span>
                                        </th>
                                        <th style="width:12%">
                                            <span href="javascript:;">
                                                {{ $t('Invoice') }}
                                            </span>
                                        </th>
                                        <th style="width:12%">
                                            <span href="javascript:;">
                                                {{ $t('Unprocess') }}
                                            </span>
                                        </th>
                                        <th style="width:12%">
                                            <span href="javascript:;">
                                                {{ $t('Billed/Unbilled') }}
                                            </span>
                                        </th>
                                        <th style="min-width: 148px;">
                                            <span href="javascript:;">
                                                {{ $t('RateSchedule') }}
                                            </span>
                                        </th>
                                        <th style="width:12%">
                                            <span href="javascript:;">
                                                {{ $t('BillingRule') }}
                                            </span>
                                        </th>
                                        <th style="width:14%">
                                            <span href="javascript:;">
                                                {{ $t('Report') }}
                                            </span>
                                        </th>
                                    </tr>
                                </thead>
                                <tbody>
                                    <tr v-for="(c, index) in DetailsData" :key="index">
                                        <td class="text-center">
                                            {{ index + 1 }}
                                        </td>
                                        <td style="width:20%">
                                            <span v-html="c.contractName"></span>
                                        </td>
                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isFlag" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isInvoice" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isUnprocess" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isBilledUnbilled" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isRateSchedule" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isBillingRule" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>

                                        <td>
                                            <label class="switch">
                                                <input type="checkbox" v-model="c.isReport" disabled>
                                                <span class="slider round">
                                                    <span class="slider-yes">Yes</span>
                                                    <span class="slider-no">No</span>
                                                </span>
                                            </label>
                                        </td>
                                    </tr>

                                    <tr v-if="DetailsData.length === 0">
                                         <td class="text-center text-danger no-record" colspan="4">{{ $t('NoRecordfound') }}</td>                                        
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        GroupName: {
            type: String,
            required: false,
        },
        GroupId: {
            type: Number,
            required: true
        },
        GroupBy: {
            type: String,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
             isShown: false,
            contractName:'',
            DetailsData: [{
                clientId: 0,
                biller: '',
                isFlag: false,
                isInvoice: false,
                isUnprocess: false,
                isBilledUnbilled: false,
                isRateSchedule: false,
                isBillingRule: false,
                isReport: false
            }],
            buttons: [{
                type: "button",
                class: "btn btn-danger",
                text: "<i class='fa fa-close pr-2'></i>Close",
                onClick: this.Close,
            }]
        }
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  
            }, 50);
        });
    },
    computed: {
        modalTitle() {
            const text = `${this.GroupBy} : ${this.GroupName}`;
            return text.length > 90 ? text.substring(0, 90) + '...' : text;
        },
        allFlag: {            
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isFlag === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isFlag = value;
                });
            }
        },

        allInvoice: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isInvoice === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isInvoice = value;
                });
            }
        },

        allUnprocess: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isUnprocess === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isUnprocess = value;
                });
            }
        },

        allBilledUnbilled: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBilledUnbilled === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBilledUnbilled = value;
                });
            }
        },

        allRateSchedule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isRateSchedule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isRateSchedule = value;
                });
            }
        },

        allBillingRule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBillingRule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBillingRule = value;
                });
            }
        },

        allReport: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isReport === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isReport = value;
                });
            }
        }
    },
    
    created: async function () {
        var vm = this;
        await vm.GetContractBillerList();       
    },
    methods: {
        GetContractBillerList() {
            var vm = this;
            var url = `groupId=${vm.GroupId}&groupBy=${vm.GroupBy}`;
            DataService.GetContractBillerList(url).then(response => {
                if (response.status === 200 && response.data?.result) {
                    let resultData = response.data.result;

                    if (typeof resultData === "string") {
                        resultData = JSON.parse(resultData);                       
                    }
                    // 🔥 push API result back into edit payload
                    vm.handleChildSubmit({
                        AssignBiller: resultData
                    });
                }
            });
        },
        handleChildSubmit(payload) {          
            const vm = this;
            if (!payload?.AssignBiller) {
                vm.DetailsData = [];
                return;
            }
            // 🔥 Convert object → array if needed
            const list = Array.isArray(payload.AssignBiller)
                ? payload.AssignBiller
                : [payload.AssignBiller];

            vm.DetailsData = list.map(c => ({
                clientId: c.CHILD_USER_ID || c.ClientIds,
                contractName: c.CHILD_NAME || c.GroupInfo || c.GroupName,
                selected: true,

                isFlag: Boolean(c.IsFlag),
                isInvoice: Boolean(c.IsInvoice),
                isUnprocess: Boolean(c.IsUnprocess),
                isBilledUnbilled: Boolean(c.IsBilledUnBilled ?? c.IsBilledUnbilled),
                isRateSchedule: Boolean(c.IsRateSchedule),
                isBillingRule: Boolean(c.IsBillingRule),
                isReport: Boolean(c.IsReport),

                parentId: c.PARENT_ID || c.GroupId,
                parentName: c.PARENT_NAME || c.GroupInfo
            })).sort((a, b) =>
                (a.contractName || '').localeCompare(
                    b.contractName || '',
                    undefined,
                    { sensitivity: 'base' } // ignores case
                )
            );
        },        
        Close: function () {
            this.$parent.isBillerDetail = false;
        }
    }
}
</script>
