<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
        <div role="document" class="modal-dialog" style="max-width: 1000px !important;">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full d-flex">
                    <h4 class="modal-title">{{ $t('AvailableContracts') }}</h4>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>

                <div class="modal-body">
                    <div class="pt-2 d-inline-block w-100">
                        <div class="col-12 p-0 mt-0">
                            <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pr-1 pl-0">
                                <input id="txtSelectedColumnsInSetup" maxlength="50" class="form-control" type="text" v-model="Searchtext" placeholder="Search by Contract Name." autocomplete="off">
                            </div>
                            <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pl-0">
                                <div class="search-btm-btn background-0  form-check-inline">
                                    <button title="Search" @click="SearchButton(Searchtext)" class="btn btn-success mr-1 px-4" data-original-title="Search">
                                        <em class="fa fa-search"></em> Search
                                    </button>
                                    <button title="Clear" class="btn btn-danger px-4" @click="Clear()" data-original-title="Clear">
                                        <em class="fa fa-refresh"></em> Clear
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div class="listing">
                        <div class="table-responsive table-fix-header">
                            <table class="table table-bordered">
                                <thead class="thead-bg">
                                    <tr>
                                        <th style="width:5%" class="text-center">
                                            <label class="form-check form-check-inline">
                                                <div class="custom-control custom-checkbox custom-control-inline">
                                                    <input type="checkbox" id="talygenAssetCheckAll" class="chkitems1 custom-control-input" :checked="selectAll" @change="selectAllItems" name="selectedItems1">
                                                    <label class="custom-control-label" for="talygenAssetCheckAll"></label>
                                                </div>
                                            </label>
                                        </th>
                                        <th scope="col">{{ $t("ConditionName") }}</th>

                                    </tr>
                                </thead>
                                <tbody>
                                    <!-- {{ContractData}} -->
                                    <tr v-for="(item,index) in ContractData" :key="index">
                                        <td class="text-center">
                                            <label class="form-check form-check-inline">
                                                <div class="custom-control custom-checkbox custom-control-inline">
                                                    <input type="checkbox" :id="'tabletablebordered' + index" class="chkitems custom-control-input" v-model="selectedItems" @change="updateSelectAll" name="selectedItems" :value="item.CHILD_USER_ID">
                                                    <label :for="'tabletablebordered' + index" class="custom-control-label"></label>
                                                </div>
                                            </label>
                                        </td>

                                        <td>
                                            <div class="text"  :title="item.CHILD_NAME" v-html="item.CHILD_NAME"> </div>
                                            
                                        </td>
                                    </tr>

                                    <tr v-if="!ContractData || ContractData.length === 0">
                                        <td colspan="6" class="text-danger text-center border-0">
                                            {{ $t("NorecordfoundText") }}
                                        </td>
                                    </tr>

                                </tbody>
                                
                            </table>
                        </div>
                        <Pager :numberofrecords="TotalRecords" :callbackfunction="GetAvailableContracts"
                                    :prevText="$t('Previous')" :nextText="$t('Next')" :firstText="$t('First')"
                                    :lastText="$t('Last')" v-on:SetCurrentPage="SetCurrentPage"></Pager>
                        <dynamic-form lang="en" ref="AvailableContract" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'>
                        </dynamic-form>
                    </div>
                    <!-- <section class="available-cont">
                        <tg-list :IsShowAction="false" ModuleName="Billing" SubModuleCode="Billing" :LegendArray="[]" :RenderRowActionMethod="renderActions" 
                        v-on:ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="CHILD_USER_ID" :listType="['List']" :ListData="ContractData" 
                        :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="topSearchFields" :IsSearchFieldsOnTop="true" 
                        SearchPosition="top" :ListDataCallBackFunction="GetAvailableContracts" :showCheckBox="true" :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" 
                        :HeaderText="$t('')" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
                         v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
                            <template v-slot:slotdata="{ data }">
                                <template v-if="data.column.COLUMN_NAME === 'CHILD_NAME'">
                                    <div class="text"  :title="data.row.CHILD_NAME"
                                        v-html="data.row.CHILD_NAME">
                                    </div>
                                </template>
                            </template>
                        </tg-list>
                        <dynamic-form lang="en" ref="AvailableContract" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'>
                        </dynamic-form>
                    </section> -->
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
import Pager from '../../components/Common/PagerContract.vue';

export default {
    components: { Pager },
    data() {
        return {
            listheaderbuttons: [],
            listActions: [],
            isLoading: false,
            isShown: false,
            ContractData: [],
            AllContractData: [],
            selectedItems: [],
            selectAll: false,
            AssignBiller: [],
            SortBy: '',
            SortExp: '',
            PageSize: 100,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            Searchtext: '',
            FormSchema: [],
            topSearchFields: [{
                fieldName: 'Search by Contract Name.',
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "ContractName",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            Headers: [{
                "COLUMN_NAME": "CHILD_NAME",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": 'Contract Name',
                "DISPLAY_ORDER": 1,
                settings: {
                    isInSlot: true
                }
            }, ],
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Next",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close
                }
            ]
        };
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;
            }, 50);
        });
    },
    created: async function () {
        await this.GetAvailableContracts();
    },
    methods: {
        async GetAvailableContracts() {
            debugger;
            const vm = this;
            vm.isLoading = true;
            //vm.PageSize *= 10;
            const url = `pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&reqFrom=MANAGEBILLER&search=${vm.searchCondition}&userId=&screenName=`;
            await DataService.GetAvailableContracts(url).then((response) => {
                debugger;
                try {
                    if (response?.data?.result) {
                        vm.ContractData = (response?.data?.result || "null");
                        vm.AllContractData = response.data.result; // keep original
                        vm.ContractData = [...vm.AllContractData]; // display copy
                        vm.TotalRecords = vm.ContractData[0].TOTAL_RECORDS; // / 10;
                        vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                        vm.CurrentPage = vm.PageNumber;
                        vm.noRecords = false;
                        vm.isLoading = false;
                    } else {
                        vm.ContractData = [];
                        vm.noRecords = true;
                        vm.TotalRecords = 0
                        vm.isLoading = false;
                    }
                } catch (e) {
                    console.error("Error parsing contract result:", e);
                }
            })

        },

        SearchButton(txt) {
            const searchTxt = (txt || "").trim().toLowerCase();
            if (!searchTxt) {
                this.ContractData = [...this.AllContractData];
                return;
            }
            this.ContractData = this.AllContractData.filter(c => c.CHILD_NAME &&
                c.CHILD_NAME.toLowerCase().includes(searchTxt)
            );
        },

        Clear() {
            this.searchCondition = "";
            this.ContractData = [...this.AllContractData];
        },

        selectAllItems() {
            var vm = this;
            vm.selectAll = !vm.selectAll;
            if (vm.selectAll) {
                vm.ContractData.forEach(function (item) {
                    vm.selectedItems.push(item.CHILD_USER_ID);
                })
            } else {
                vm.selectedItems = [];
            }
        },
        updateSelectAll() {
            var vm = this;
            const totalItems = vm.ContractData.length;
            const selectedCount = vm.selectedItems.length;
            vm.selectAll = totalItems > 0 && selectedCount === totalItems;
        },

        onSubmit(formfields) {
            debugger;
            var vm = this;
            if (vm.selectedItems) {
                vm.AssignBiller = vm.ContractData.filter(x => vm.selectedItems.includes(x.CHILD_USER_ID));
                const payload = {
                    formfields: formfields,
                    AssignBiller: vm.AssignBiller
                };
                vm.$emit('submit-data', payload);
                vm.$parent.isAddContract = false;

            } else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }

        },

         SetCurrentPage: function (x) {
            this.PageNumber = x.PageNumber;
            this.PageSize = x.PageSize;
        },

        //onSubmit(formfields) {
        //     debugger;
        //     var vm = this;
        //     var val = "";
        //     vm.isLoading = true;
        //     $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
        //         if (val.length > 0)
        //             val += ',';
        //         val += $(this).val();
        //     });
        //     if (val != null) {
        //         const ids = val.toString().split(',').map(Number);
        //         vm.AssignBiller = vm.ContractData.filter(item => ids.includes(item.CHILD_USER_ID));
        //         const payload = {
        //             formfields: formfields,
        //             AssignBiller: vm.AssignBiller
        //         };
        //         vm.$emit('submit-data', payload);
        //         vm.$parent.isAddContract = false;

        //     } else {
        //         vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
        //     }

        // },

        Close() {
            this.$parent.isAddContract = false;
        },

        leftCommonSearch: function (value) {

        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {

            }
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            //this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            //this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            // self.listActions.forEach(actionItem => {
            //     let action = {
            //         ...actionItem
            //     };
            //     switch (action.title) {

            //     }
            //     rtnActionArray.push(action);
            // });
            return rtnActionArray;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {

            }
        },
    }
};
</script>

<style>
.available-cont .ticketsmallfix {
    display: none;
}

.available-cont .container-fluid.mt-2.p-0 {
    margin-top: 0 !important;
}

.available-cont #crmleftsearch {
    border: none !important;
    padding: 0 !important;
}

.available-cont #crmleftsearch .col-md-3.col-lg-3.col-xl-3 {
    max-width: 55%;
    flex: 0 0 55%;
    padding-left: 0 !important;
}
</style>
