<template>
<section>
    <loader :is-visible="isLoading"></loader>
    <tg-list :IsShowAction="true" ModuleName="" SubModuleCode="" :LegendArray="[]"
        :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
        IdentityColumn="" :listType="['List']" :ListData="BillerData" :HeaderData="Headers"
        :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
        IsSearchFieldsOnTop="true" :ListDataCallBackFunction="FetchData" :showCheckBox="true"
        :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" :HeaderText="$t('ManageBiller')"
        v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
        v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
        <template v-slot:slotdata="{ data }"> 
                <template v-if="['GroupName','GroupInfo'].includes(data.column.COLUMN_NAME) && data.column.DISPLAY_ORDER==2">
                    <td class="text single-action tourguide_a" >
                        <a v-if="data.column.COLUMN_NAME=='GroupName'" @click="GetContractBillerList(data.row)" :title="data.row.GroupName">
                            <em class="fa fa-eye text-info"></em> {{ data.row.GroupName }}
                        </a>
                        <a v-if="data.column.COLUMN_NAME=='GroupInfo'" @click="GetContractBillerList(data.row)" :title="data.row.GroupInfo">
                            <em class="fa fa-eye text-info"></em> {{data.row.GroupInfo}}
                        </a>
                    </td>
                </template>       
                <template v-if="data.column.COLUMN_NAME == 'CreatedAt'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.CreatedAt">
                        {{ formatDate(data.row.CreatedAt) }}
                    </td>
                </template>
        </template>
    </tg-list>
    <AssignBiller v-if="isAddBiller" :GroupBy="GroupBy" :editPayload="editPayload"></AssignBiller>
    <BillerDetails v-if="isBillerDetail"  :GroupBy="GroupBy" :GroupId="GroupId" :GroupName="GroupName"></BillerDetails>
</section>
</template>

<script>
import Schema from "../Biller/Schema.js";
import DataService from "../../services/DataService.js";
import AssignBiller from "../Biller/AssignBiller.vue";
import BillerDetails from "./BillerDetails.vue";
import { locateBillingService } from "../../services/locateBillingService";

export default {
    components: { AssignBiller, BillerDetails },
    data() {
        return {
            isLoading: false,
            Headers: [                
                {
                    "COLUMN_NAME": "GroupInfo",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Biller Name',
                    "DISPLAY_ORDER": 1,
                    // settings: {
                    //     isInSlot: false
                    // }
                },
                {
                    "COLUMN_NAME": "GroupName",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Contracts',
                    "DISPLAY_ORDER": 2,
                        settings: {
                            isInSlot: true
                        }
                },                
                {
                    "COLUMN_NAME": "CreatedBy",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CreatedBy'),
                    "DISPLAY_ORDER": 3,
                    // settings: {
                    //     isInSlot: false
                    // }
                },
                {
                    "COLUMN_NAME": "CreatedAt",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CreatedAt'),
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            BillerData: [],
            editPayload: null,
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            leftSearchFields: Schema.leftsearchSchema,
            CompanyId: null,
            UserId: null,
            isAddBiller: false,
            isBillerDetail: false,
            GroupId:0,
            GroupBy:'Biller',
            clientId:'',
            BillerId:''
        }
    },
     computed: {
        allFlag: {            
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isFlag === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isFlag = value;
                });
            }
        },

        allInvoice: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isInvoice === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isInvoice = value;
                });
            }
        },

        allUnprocess: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isUnprocess === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isUnprocess = value;
                });
            }
        },

        allBilledUnbilled: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBilledUnbilled === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBilledUnbilled = value;
                });
            }
        },

        allRateSchedule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isRateSchedule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isRateSchedule = value;
                });
            }
        },

        allBillingRule: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isBillingRule === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isBillingRule = value;
                });
            }
        },

        allReport: {
            get() {
                if (!this.receivedData.length) return false;
                return this.receivedData.every(c => c.isReport === true);
            },
            set(value) {
                this.receivedData.forEach(c => {
                    c.isReport = value;
                });
            }
        }
    },
    created: async function () {
        var vm = this;
        this.$router.replace({ query: {} });
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        await vm.FetchData();
        await vm.fetchclientlist();
        await Schema.bindleftCommonSearchdropdown(vm, "BILLER", "BILLER");
        //await Schema.bindleftCommonSearchdropdown(vm, "BILLER", "CONTRACT");
        
    },
    methods: {
        formatDate(date) {
            if (!date) return '--';
            return new Date(date).toLocaleString();
        },
         fetchclientlist: async function () {
            var vm = this;
            vm.isLoading = true;
            //var url = `reqFrom=CUSTOM`;
            var url = `reqFrom=MANAGEBILLER`;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList = response.data.items || [];
                // Populate the client dropdown in leftSearchFields
                vm.leftSearchFields.find(f => f.fieldName === 'CONTRACT').listOptions = vm.clientList;
            } catch (error) {
                vm.clientList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'CONTRACT').listOptions = [];
                console.error('Error fetching client list:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        AddBiller(){
            var vm = this;
            vm.editPayload= null,
            vm.isAddBiller = true;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case "Edit":
                    this.EditBiller(item);
                    break;
                case "Delete":
                    this.DeleteBiller(item);
                    break;
            }
        },
        EditBiller(item) {
            this.editPayload = {
                formfields: '',
                AssignBiller: [item]
            };
            this.isAddBiller = true;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            this.BillerId = '';
            this.clientId = '';
            this.searchCondition = '';

            if (value?.searchConditionJson) {
                const params = new URLSearchParams(value.searchConditionJson);
                this.BillerId = params.get('BillerIds') || '';
                this.clientId = params.get('ClientIds') || '';

            } else if (value?.searchCondition) {
                this.searchCondition = value.searchCondition;
            }
            this.FetchData();
        },

        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddBiller":
                    this.AddBiller();
                    break;
                case "GroupByContract":
                    this.GroupByContract();
                    break;
                case "GroupByBiller":
                    this.GroupByBiller();
                    break;
            }
        },
        GetContractBillerList(item){
            var vm=this;
            vm.GroupName= vm.GroupBy=='Biller'? item.GroupInfo :item.GroupName;                       
            vm.GroupId= item.GroupId;                       
            vm.isBillerDetail = true;       
        },
        GroupByContract(){
            var vm=this;
            vm.GroupBy='Contract';
            vm.listheaderbuttons[1].isvisible=false;
            vm.listheaderbuttons[2].isvisible=true;
            vm.FetchData();
        },
        GroupByBiller(){
            var vm=this;
            vm.GroupBy='Biller';
            vm.listheaderbuttons[2].isvisible=false;
            vm.listheaderbuttons[1].isvisible=true;
            vm.FetchData();           
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                    case 'Delete':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },       
        FetchData: async function () {
            var vm = this;
            vm.isLoading = true;
            vm.TotalRecords=0;
            var params = `groupBy=${vm.GroupBy}&billerIds=${vm.BillerId}&clientIds=${vm.clientId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&isPartial=${0}`           
            await DataService.GetBillerListing(params).then((response) => {
                if (response.data.result.length > 0 && response.data.result!='[]') {
                        if (vm.GroupBy === 'Biller') {
                            vm.Headers = vm.Headers.map(h => {
                                if (h.COLUMN_NAME === 'GroupInfo') {
                                    return {
                                        ...h,
                                        DISPLAY_ORDER: 1,
                                        settings: { isInSlot: false }
                                    };
                                }
                                if (h.COLUMN_NAME === 'GroupName') {
                                    return {
                                        ...h,
                                        DISPLAY_ORDER: 2,
                                        settings: { isInSlot: true }
                                    };
                                }
                                return h;
                            });

                        } else {
                            vm.Headers = vm.Headers.map(h => {
                                if (h.COLUMN_NAME === 'GroupName') {
                                    return {
                                        ...h,
                                        DISPLAY_ORDER: 1,
                                        settings: { isInSlot: false }
                                    };
                                }
                                if (h.COLUMN_NAME === 'GroupInfo') {
                                    return {
                                        ...h,
                                        DISPLAY_ORDER: 2,
                                        settings: { isInSlot: true }
                                    };
                                }
                                return h;
                            });
                        }
                        vm.Headers.sort((a, b) => a.DISPLAY_ORDER - b.DISPLAY_ORDER);

                    vm.BillerData = JSON.parse(response.data.result);
                    vm.TotalRecords = vm.BillerData[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;                   
                    vm.noRecords = false;
                    vm.isLoading = false;
                } else {
                    vm.BillerData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        },
        DeleteBiller(item) {
            var vm = this;
            if (!item || !item.GroupId) {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
                return;
            }
            vm.confirmR(vm.$t("ConfirmDelete"), true, vm.$t("Delete") + " " + vm.$t("Biller"),
                function () {
                    vm.isLoading = true;
                    var biller=vm.GroupBy ? vm.GroupBy : 'Biller';
                    var url = `groupId=${item.GroupId}&groupBy=${biller}`;

                    DataService.DeleteAssignBiller(url).then(function (response) {
                        if (response.status === 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Biller')]),"success",true,vm.$t("Alert"));
                            vm.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Biller')]),"error",true,vm.$t("Alert"));
                        }
                        vm.isLoading = false;
                    });
                }
            );
        }
     
    }
}
</script>